// Pull both per-index ensures into the proof context so their triggers
// (`post1_self_@[index].is_None()` and `post2_self_@[index].is_None()`)
// fire on the same `index` bindings.
assert(forall|index: int| 0 <= index < N ==> #[trigger] post1_self_@[index].is_None());
assert(forall|index: int| 0 <= index < N ==> #[trigger] post2_self_@[index].is_None());

// Lengths line up via `wf` on both post-states.
assert(post1_self_.wf());
assert(post2_self_.wf());
assert(post1_self_@.len() == N);
assert(post2_self_@.len() == N);

// Pointwise: every index is `None` in both runs, hence the elements are equal.
assert forall|i: int| 0 <= i < N implies post1_self_@[i] == post2_self_@[i] by {
    assert(post1_self_@[i].is_None());
    assert(post2_self_@[i].is_None());
}

// Sequence extensionality lifts the pointwise equality to view equality.
assert(post1_self_@ =~= post2_self_@);
